# Implement the requested checks directly (columns).
from collections import Counter

def parse_puzzle_from_context():
    text = CONTEXT.read(0, None)
    lines = [l.strip() for l in text.splitlines()]
    # find ORIGINAL_PUZZLE and SOLUTION_PUZZLE blocks
    def extract_block(label):
        try:
            idx = lines.index(label)
        except ValueError:
            return None
        block = []
        for l in lines[idx+1:idx+10]:
            if l and all(ch.isdigit() for ch in l) and len(l) >= 9:
                block.append(l[:9])
            else:
                break
        if len(block) == 9:
            return block
        return None

    original = extract_block("ORIGINAL_PUZZLE:")
    solution = extract_block("SOLUTION_PUZZLE:")
    return original, solution

ORIG, SOL = parse_puzzle_from_context()
if SOL is None:
    raise RuntimeError("Couldn't find SOLUTION_PUZZLE in CONTEXT")

def invalid_columns(board_lines):
    # board_lines: list of 9 strings, each 9 digits
    invalid = []
    for c in range(9):
        col = [board_lines[r][c] for r in range(9)]
        counts = Counter(col)
        digits_set = set(col)
        issues = []
        if digits_set != set("123456789"):
            missing = sorted(set("123456789") - digits_set)
            extras = sorted(d for d, cnt in counts.items() if cnt > 1)
            if missing:
                issues.append("missing:"+ "".join(missing))
            if extras:
                issues.append("duplicates:"+ "".join(extras))
        if issues:
            invalid.append(c)
    return invalid

invalids = invalid_columns(SOL)

# Build final 9-item result list including checks for given-cell consistency and column validity.
results = []
for c in range(9):
    issues = []
    # check given-cell consistency if ORIGINAL present
    if ORIG is not None:
        for r in range(9):
            o = ORIG[r][c]
            if o != '0':
                s = SOL[r][c]
                if s != o:
                    issues.append(f"given-mismatch at row {r}: orig={o} sol={s}")
    # check column digits
    col = [SOL[r][c] for r in range(9)]
    if set(col) != set("123456789"):
        counts = Counter(col)
        missing = sorted(set("123456789") - set(col))
        duplicates = sorted(d for d, cnt in counts.items() if cnt > 1)
        if missing:
            issues.append("missing:" + "".join(missing))
        if duplicates:
            issues.append("duplicates:" + "".join(duplicates))
    ok = len(issues) == 0
    results.append({"index": c, "ok": ok, "issue": "" if ok else "; ".join(issues)})

# As requested, show invalid columns and then finish with the structured result.
print("invalid_columns:", invalids)
done(results)
